class Solution:
    def maximumBinaryString(self, binary: str) -> str:
        n = len(binary)
        i = 0
        while i < n and binary[i] == '1':
            i += 1
        if i == n:
            return binary
        res = '1' * i
        j = i
        while j < n and binary[j] == '0':
            j += 1
        if j == n:
            res += '1' + '0' * (n - i - 1)
        else:
            res += '0' + '1' * (n - j)
        return res

